-- ============================================================================
-- Quiz Seed: 2 Chronicles — Part 1 (Chapters 1–12)
-- 3 kids + 5 teens + 8 adults = 16 questions × 12 chapters = 192 total questions
-- ============================================================================

-- ═══ 2 Chronicles Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 1, 'kids', 1, 'Where did Solomon go to worship God at the beginning of his reign?', 'Gibeon', 'Jerusalem', 'Bethlehem', 'Hebron', 'a', '2 Chronicles 1:3 — "So Solomon, and all the congregation with him, went to the high place that was at Gibeon."'),
('2 Chronicles', 1, 'kids', 2, 'What did Solomon ask God to give him?', 'Wisdom and knowledge', 'Gold and silver', 'A long life', 'Victory in battle', 'a', '2 Chronicles 1:10 — "Give me now wisdom and knowledge, that I may go out and come in before this people."'),
('2 Chronicles', 1, 'kids', 3, 'Because Solomon asked for wisdom, what did God also give him?', 'Riches and wealth and honour', 'A mighty army', 'Many sons', 'A beautiful palace', 'a', '2 Chronicles 1:12 — "Wisdom and knowledge is granted unto thee; and I will give thee riches, and wealth, and honour, such as none of the kings have had that have been before thee."'),
-- Teens
('2 Chronicles', 1, 'teens', 1, 'What was kept at Gibeon that Solomon went there to worship?', 'The tabernacle of the congregation and the brasen altar that Moses had made', 'The ark of the covenant', 'The original stone tablets', 'The altar of incense', 'a', '2 Chronicles 1:5 — "Moreover the brasen altar, that Bezaleel the son of Uri...had made, he put before the tabernacle of the LORD."'),
('2 Chronicles', 1, 'teens', 2, 'How many burnt offerings did Solomon offer at Gibeon?', 'A thousand burnt offerings', 'Five hundred burnt offerings', 'Three thousand burnt offerings', 'Seven burnt offerings', 'a', '2 Chronicles 1:6 — "And Solomon went up thither to the brasen altar before the LORD...and offered a thousand burnt offerings upon it."'),
('2 Chronicles', 1, 'teens', 3, 'What did God say to Solomon in the night at Gibeon?', 'Ask what I shall give thee', 'I am the LORD thy God, fear not', 'Write down all my statutes', 'Build me a house in Jerusalem', 'a', '2 Chronicles 1:7 — "In that night did God appear unto Solomon, and said unto him, Ask what I shall give thee."'),
('2 Chronicles', 1, 'teens', 4, 'What did Solomon say he had NOT asked for when God offered him anything?', 'Riches, wealth, honour, the life of his enemies, or long life', 'Victory in war', 'A great kingdom', 'Fame among all nations', 'a', '2 Chronicles 1:11 — "Thou hast not asked riches, wealth, or honour, nor the life of thine enemies, neither yet hast asked long life."'),
('2 Chronicles', 1, 'teens', 5, 'What did Solomon import in large numbers to build up his military strength?', 'Horses and chariots from Egypt and from all other countries', 'Iron weapons from the Philistines', 'War elephants from Arabia', 'Bronze armour from Tyre', 'a', '2 Chronicles 1:16 — "And Solomon had horses brought out of Egypt, and linen yarn: the king''s merchants received the linen yarn at a price."'),
-- Adults
('2 Chronicles', 1, 'adults', 1, 'Where was the ark of God kept when Solomon went to Gibeon, and who had brought it there?', 'In Jerusalem, in the tent that David had pitched for it', 'In Shiloh where it had always been', 'At Gibeon inside the tabernacle', 'At Bethel with the Levites', 'a', '2 Chronicles 1:4 — "But the ark of God had David brought up from Kirjath-jearim to the place which David had prepared for it: for he had pitched a tent for it at Jerusalem."'),
('2 Chronicles', 1, 'adults', 2, 'On what basis did Solomon frame his request for wisdom — what role did he acknowledge he was called to fill?', 'He was made king over a people like the dust of the earth in multitude, and needed wisdom to lead them', 'He was the youngest of David''s sons and felt unqualified', 'He had been charged by David to build the temple and needed knowledge for it', 'He was surrounded by hostile nations and needed military counsel', 'a', '2 Chronicles 1:10 — "Give me now wisdom and knowledge...for who can judge this thy people, that is so great?"'),
('2 Chronicles', 1, 'adults', 3, 'What does God''s statement "wisdom and knowledge is granted unto thee" reveal about the nature of Solomon''s reign from its outset?', 'That God himself confirmed and equipped Solomon''s rule, making his wisdom a divine gift rather than human achievement', 'That Solomon had studied all available scrolls diligently', 'That the priests at Gibeon had trained him from childhood', 'That the gift was conditional upon his completing the temple', 'a', '2 Chronicles 1:12 — "Wisdom and knowledge is granted unto thee; and I will give thee riches, and wealth, and honour," showing God''s direct bestowal.'),
('2 Chronicles', 1, 'adults', 4, 'What was the scale of Solomon''s commercial activity in horses and chariots according to this chapter?', 'He gathered chariots and horsemen so that he had 1,400 chariots and 12,000 horsemen, buying at fixed prices for Hittite and Syrian kings', 'He imported only from Egypt', 'He relied entirely on tribute from conquered nations', 'He inherited David''s army without expansion', 'a', '2 Chronicles 1:14 — "And Solomon gathered chariots and horsemen: and he had a thousand and four hundred chariots, and twelve thousand horsemen."'),
('2 Chronicles', 1, 'adults', 5, 'What economic detail shows the abundance of Solomon''s kingdom regarding silver and gold?', 'The king made silver and gold as plenteous in Jerusalem as stones, and cedar as sycamore trees', 'Gold was stored only in the temple treasury', 'Silver was rationed among the twelve tribes', 'Taxes were paid only in cedar timber', 'a', '2 Chronicles 1:15 — "And the king made silver and gold at Jerusalem as plenteous as stones, and cedar trees made he as the sycamore trees that are in the vale for abundance."'),
('2 Chronicles', 1, 'adults', 6, 'What was the price of a chariot from Egypt and of a horse, revealing the trade economics of Solomon''s time?', 'A chariot cost six hundred shekels of silver and a horse one hundred and fifty shekels', 'A chariot cost one hundred shekels and a horse fifty shekels', 'A chariot cost a talent of gold and a horse ten shekels', 'Prices varied by season and were not fixed', 'a', '2 Chronicles 1:17 — "And they fetched up, and brought forth out of Egypt a chariot for six hundred shekels of silver, and an horse for an hundred and fifty."'),
('2 Chronicles', 1, 'adults', 7, 'What role did Solomon''s merchants play in the regional horse trade?', 'They exported horses and chariots to all the kings of the Hittites and of Syria', 'They only supplied Solomon''s own army', 'They operated under Egyptian license', 'They sold only within Israel''s borders', 'a', '2 Chronicles 1:17 — "And so brought they out horses for all the kings of the Hittites, and for the kings of Syria, by their means."'),
('2 Chronicles', 1, 'adults', 8, 'How does the Chronicler''s account of Solomon''s accession differ in emphasis from Kings by starting with the Gibeon episode?', 'The Chronicler highlights Solomon''s wholehearted seeking of God as the foundation of his blessed reign', 'The Chronicler is more interested in military history', 'The Chronicler omits the covenant with Pharaoh', 'The Chronicler focuses on the tax system first', 'a', '2 Chronicles 1:1 — "And Solomon the son of David was strengthened in his kingdom, and the LORD his God was with him, and magnified him exceedingly," setting a theological tone for the reign.');

-- ═══ 2 Chronicles Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 2, 'kids', 1, 'What building project did Solomon plan and prepare for?', 'A house for the name of the LORD and a house for his kingdom', 'A great city wall around Jerusalem', 'A harbour for his navy', 'A school for wisdom', 'a', '2 Chronicles 2:1 — "And Solomon determined to build an house for the name of the LORD, and an house for his kingdom."'),
('2 Chronicles', 2, 'kids', 2, 'What did Solomon ask the king of Tyre to send him for the building project?', 'A man cunning to work in gold, silver, brass, and other materials', 'A thousand soldiers to guard the temple', 'Ships to carry cedar from Lebanon', 'Silver enough to pay all the workers', 'a', '2 Chronicles 2:7 — "Send me now therefore a man cunning to work in gold, and in silver, and in brass, and in iron."'),
('2 Chronicles', 2, 'kids', 3, 'What did Solomon promise to send King Huram of Tyre in exchange for the timber and skilled workers?', 'Wheat, barley, wine, and oil', 'Gold and silver', 'Livestock and cloth', 'Spices and precious stones', 'a', '2 Chronicles 2:15 — "Now therefore the wheat, and the barley, the oil, and the wine, which my lord hath spoken of, let him send unto his servants."'),
-- Teens
('2 Chronicles', 2, 'teens', 1, 'How many labourers did Solomon conscript to carry burdens for the building project?', 'Seventy thousand to bear burdens and eighty thousand hewers in the mountain', 'Twenty thousand to carry and forty thousand to cut stone', 'Thirty thousand men total sent in shifts', 'One hundred thousand men from the tribes of Israel', 'a', '2 Chronicles 2:2 — "And Solomon told out threescore and ten thousand men to bear burdens, and fourscore thousand to hew in the mountain."'),
('2 Chronicles', 2, 'teens', 2, 'What did Solomon say about the temple, acknowledging God cannot be contained?', 'The heaven and heaven of heavens cannot contain him, so who is he to build him a house', 'The temple would be the greatest wonder of all nations', 'No house could be worthy, so only the best cedar must be used', 'The temple must stand forever because God lives there', 'a', '2 Chronicles 2:6 — "But who is able to build him an house, seeing the heaven and heaven of heavens cannot contain him?"'),
('2 Chronicles', 2, 'teens', 3, 'What was the name of the craftsman King Huram sent to Solomon?', 'Huram-abi, skilled in all manner of craft', 'Adoniram, master of bronze', 'Bezaleel, the son of Uri', 'Hiram, the chief architect', 'a', '2 Chronicles 2:13 — "And now I have sent a cunning man, endued with understanding, of Huram my father''s."'),
('2 Chronicles', 2, 'teens', 4, 'What was Huram-abi''s mother''s tribal background according to the text?', 'She was of the daughters of Dan', 'She was of the tribe of Levi', 'She was a woman of Tyre', 'She was of the tribe of Judah', 'a', '2 Chronicles 2:14 — "The son of a woman of the daughters of Dan, and his father was a man of Tyre."'),
('2 Chronicles', 2, 'teens', 5, 'How many overseers did Solomon appoint to set the people to work?', 'Three thousand and six hundred', 'One thousand two hundred', 'Five hundred and fifty', 'Two thousand four hundred', 'a', '2 Chronicles 2:18 — "And he set threescore and ten thousand of them to be bearers of burdens, and fourscore thousand to be hewers in the mountain, and three thousand and six hundred overseers to set the people a work."'),
-- Adults
('2 Chronicles', 2, 'adults', 1, 'What theological reason did Solomon give Huram for why the temple must be great and wonderful?', 'For great is our God above all gods, and no one can build him a house since the heavens cannot contain him, yet Solomon would burn incense before him', 'Because Israel was the greatest nation and deserved the greatest temple', 'To show all surrounding nations the power of the God of Israel', 'Because David had already sworn an oath that the temple would surpass all others', 'a', '2 Chronicles 2:5 — "And the house which I build is great: for great is our God above all gods."'),
('2 Chronicles', 2, 'adults', 2, 'What four categories of material did Solomon request that Huram''s craftsman be skilled to work in?', 'Gold, silver, brass, and iron — plus purple, crimson, and blue materials, and to engrave', 'Only gold and silver for the holy vessels', 'Cedar, fir, and algum timbers only', 'Stone, clay, mortar, and hewn rock', 'a', '2 Chronicles 2:7 — "Send me now therefore a man cunning to work in gold, and in silver, and in brass, and in iron, and in purple, and crimson, and blue."'),
('2 Chronicles', 2, 'adults', 3, 'What was the annual payment Solomon promised to Huram''s servants who cut timber in Lebanon?', 'Twenty thousand measures of beaten wheat, twenty thousand measures of barley, twenty thousand baths of wine, and twenty thousand baths of oil', 'A talent of gold for every hundred logs', 'Silver paid by weight each month', 'A fixed tribute of spices and livestock', 'a', '2 Chronicles 2:10 — "And, behold, I will give to thy servants, the hewers that cut timber, twenty thousand measures of beaten wheat, and twenty thousand measures of barley, and twenty thousand baths of wine, and twenty thousand baths of oil."'),
('2 Chronicles', 2, 'adults', 4, 'How did Huram describe the God of Israel in his reply to Solomon, showing his recognition of Israel''s God?', 'Blessed be the LORD God of Israel, that made heaven and earth, who hath given to David a wise son endued with prudence and understanding', 'The God of Israel is mighty in battle and none can stand against him', 'The God of Israel has given Solomon wisdom greater than Pharaoh''s', 'Truly the LORD God is above the gods of Tyre', 'a', '2 Chronicles 2:12 — "Huram said moreover, Blessed be the LORD God of Israel, that made heaven and earth, who hath given to David the king a wise son, endued with prudence and understanding."'),
('2 Chronicles', 2, 'adults', 5, 'What specific crafts was Huram-abi said to be skilled in beyond metalwork?', 'To find out every device which shall be put to him — skilled in all crafts including purple, blue, fine linen, and carving', 'He was only a metalworker with no other skills', 'He specialized in the cutting of precious stones', 'He was an architect who designed buildings', 'a', '2 Chronicles 2:14 — "Skilful to work in gold, and in silver, in brass, in iron, in stone, and in timber, in purple, in blue, and in fine linen, and in crimson; also to grave any manner of graving, and to find out every device."'),
('2 Chronicles', 2, 'adults', 6, 'How many non-Israelite strangers did Solomon number as the labour force, and what had previously been done to count them?', '153,600 strangers, whom David had numbered', '100,000 strangers whom Solomon himself counted', '200,000 who were counted by the tribal chiefs', '70,000 counted by the Levites', 'a', '2 Chronicles 2:17 — "And Solomon numbered all the strangers that were in the land of Israel, after the numbering wherewith David his father had numbered them; and they were found an hundred and fifty and three thousand and six hundred."'),
('2 Chronicles', 2, 'adults', 7, 'What type of timber did Solomon specifically request from Lebanon beside cedar?', 'Fir trees and algum trees', 'Oak and acacia', 'Cypress and pine', 'Ebony and sandalwood', 'a', '2 Chronicles 2:8 — "Send me also cedar trees, fir trees, and algum trees, out of Lebanon: for I know that thy servants can skill to cut timber in Lebanon."'),
('2 Chronicles', 2, 'adults', 8, 'What was Solomon''s stated purpose for the algum timber from Lebanon?', 'To make stairs for the house of God and for the king''s house, and harps and psalteries for singers', 'To build ships for his navy', 'To construct the doors of the temple sanctuary', 'To fuel the altar fires perpetually', 'a', '2 Chronicles 2:8 — "And the algum trees to make algum trees in abundance: for they were not common," used later per 2 Chronicles 9:11 for stairs and instruments.');

-- ═══ 2 Chronicles Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 3, 'kids', 1, 'On what mountain did Solomon build the temple?', 'Mount Moriah', 'Mount Sinai', 'Mount Zion', 'Mount Carmel', 'a', '2 Chronicles 3:1 — "Then Solomon began to build the house of the LORD at Jerusalem in mount Moriah."'),
('2 Chronicles', 3, 'kids', 2, 'What were the names of the two pillars Solomon built at the porch of the temple?', 'Jachin and Boaz', 'Sinai and Zion', 'Aaron and Moses', 'Gold and Silver', 'a', '2 Chronicles 3:17 — "And he reared up the pillars before the temple, one on the right hand, and the other on the left; and called the name of that on the right hand Jachin, and the name of that on the left Boaz."'),
('2 Chronicles', 3, 'kids', 3, 'What precious material did Solomon use to overlay the inside of the temple?', 'Gold', 'Silver', 'Brass', 'Cedar', 'a', '2 Chronicles 3:4 — "And the porch that was in the front of the house...he overlaid it within with pure gold."'),
-- Teens
('2 Chronicles', 3, 'teens', 1, 'What was the historical significance of Mount Moriah mentioned in the text?', 'It was where the LORD appeared to David his father and where David had prepared the threshingfloor of Ornan the Jebusite', 'It was the mountain where Moses received the law', 'It was the site of Joshua''s first altar in Canaan', 'It was where Abraham first built an altar to God', 'a', '2 Chronicles 3:1 — "In the place that David had prepared in the threshingfloor of Ornan the Jebusite."'),
('2 Chronicles', 3, 'teens', 2, 'What was the length and breadth of the porch of the temple?', 'The length twenty cubits and the height one hundred and twenty cubits', 'Sixty cubits long and twenty cubits wide', 'Thirty cubits long and ten cubits high', 'Forty cubits long and twenty cubits wide', 'a', '2 Chronicles 3:4 — "And the porch that was in the front of the house, the length of it was according to the breadth of the house, twenty cubits, and the height was an hundred and twenty."'),
('2 Chronicles', 3, 'teens', 3, 'What covered the walls and beams of the most holy house?', 'Fine gold, and the gold was of Parvaim', 'Pure silver overlaid on cedar', 'Carved cherubim and palm trees in cedar', 'Bronze plates and linen hangings', 'a', '2 Chronicles 3:6 — "And he garnished the house with precious stones for beauty: and the gold was gold of Parvaim."'),
('2 Chronicles', 3, 'teens', 4, 'What was the wingspan of each of the two cherubim Solomon made for the most holy house?', 'Ten cubits each, so their wings together spanned twenty cubits', 'Five cubits each', 'Fifteen cubits each', 'Eight cubits each', 'a', '2 Chronicles 3:11 — "And the wings of the cherubims were twenty cubits long: one wing of the one cherub was five cubits...and the other wing was likewise five cubits."'),
('2 Chronicles', 3, 'teens', 5, 'What material was used to make the veil that separated the most holy place?', 'Blue, purple, crimson, and fine linen with cherubims worked on it', 'Pure white linen only', 'Gold thread woven into cedar planks', 'Purple silk embroidered with the law', 'a', '2 Chronicles 3:14 — "And he made the vail of blue, and purple, and crimson, and fine linen, and wrought cherubims thereon."'),
-- Adults
('2 Chronicles', 3, 'adults', 1, 'On what day of which month in which year of Solomon''s reign did construction begin?', 'The second day of the second month of the fourth year of his reign', 'The first day of the first month of the third year', 'The seventh month of the seventh year', 'The first day of the fourth year at the new moon', 'a', '2 Chronicles 3:2 — "And he began to build in the second day of the second month, in the fourth year of his reign."'),
('2 Chronicles', 3, 'adults', 2, 'What were the dimensions of the house of God according to the old measure?', 'The length sixty cubits and the breadth twenty cubits', 'One hundred cubits long and fifty cubits wide', 'Forty cubits by twenty cubits', 'Thirty cubits high and twenty cubits wide', 'a', '2 Chronicles 3:3 — "Now these are the things wherein Solomon was instructed for the building of the house of God. The length by cubits after the first measure was threescore cubits, and the breadth twenty cubits."'),
('2 Chronicles', 3, 'adults', 3, 'How much gold was used to overlay the upper chambers and the great house?', 'Six hundred talents of fine gold for the upper chambers and twenty talents for each story', 'A thousand talents in the most holy place alone', 'Three hundred talents for the outer house', 'All the gold of David''s treasury without a stated weight', 'a', '2 Chronicles 3:8 — "And he made the most holy house...and he overlaid it with fine gold, amounting to six hundred talents."'),
('2 Chronicles', 3, 'adults', 4, 'What was the height of the cherubims standing in the most holy place?', 'Each cherub was ten cubits high', 'Each cherub was five cubits high', 'Each cherub was fifteen cubits high', 'Each cherub was twenty cubits high', 'a', '2 Chronicles 3:13 — "The wings of these cherubims spread themselves forth twenty cubits: and they stood on their feet, and their faces were inward."'),
('2 Chronicles', 3, 'adults', 5, 'How were the cherubim oriented in the most holy house?', 'Their faces turned inward toward the house, wings stretching to the walls on each side and touching in the middle', 'They faced the entrance of the temple', 'They faced outward toward Jerusalem', 'They faced each other with wings folded', 'a', '2 Chronicles 3:13 — "And they stood on their feet, and their faces were inward," with wings spanning the full twenty cubits of the room.'),
('2 Chronicles', 3, 'adults', 6, 'How high were the pillars Jachin and Boaz, and what was on top of them?', 'Thirty-five cubits high with chapiters of five cubits on top', 'Twenty cubits high with carved pomegranates', 'Forty cubits high with bronze bowls on top', 'Eighteen cubits high with lily-work chapiters', 'a', '2 Chronicles 3:15 — "Also he made before the house two pillars of thirty and five cubits high, and the chapiter that was on the top of each of them was five cubits."'),
('2 Chronicles', 3, 'adults', 7, 'What decorative element adorned the chains placed on the pillars?', 'An hundred pomegranates', 'Golden lilies', 'Bronze rings and hooks', 'Carved palm trees', 'a', '2 Chronicles 3:16 — "And he made chains, as in the oracle, and put them on the heads of the pillars; and made an hundred pomegranates, and put them on the chains."'),
('2 Chronicles', 3, 'adults', 8, 'What is the theological significance of building the temple on Mount Moriah, the site where Abraham offered Isaac?', 'It connected the temple to the covenant of sacrifice and redemption established with Abraham, showing continuity of God''s covenant purposes', 'It was simply the highest available ground in Jerusalem', 'It was chosen because Ornan paid the highest price for his threshingfloor', 'It was selected by lot among the Levites', 'a', '2 Chronicles 3:1 — "Then Solomon began to build the house of the LORD at Jerusalem in mount Moriah, where the LORD appeared unto David his father," linking temple worship to divine encounter and Abrahamic covenant.');

-- ═══ 2 Chronicles Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 4, 'kids', 1, 'What large basin did Solomon make for the priests to wash in?', 'A molten sea', 'A golden bowl', 'A brasen laver', 'A marble fountain', 'a', '2 Chronicles 4:2 — "Also he made a molten sea of ten cubits from brim to brim, round in compass."'),
('2 Chronicles', 4, 'kids', 2, 'How many candlesticks did Solomon make for the temple?', 'Ten candlesticks of gold', 'Seven candlesticks of gold', 'Twenty candlesticks of silver', 'Five candlesticks of brass', 'a', '2 Chronicles 4:7 — "And he made ten candlesticks of gold according to their form, and set them in the temple, five on the right hand, and five on the left."'),
('2 Chronicles', 4, 'kids', 3, 'How many tables did Solomon put in the temple?', 'Ten tables', 'One table', 'Seven tables', 'Twelve tables', 'a', '2 Chronicles 4:8 — "He made also ten tables, and placed them in the temple, five on the right side, and five on the left."'),
-- Teens
('2 Chronicles', 4, 'teens', 1, 'What were the dimensions of the brasen altar Solomon made?', 'Twenty cubits long, twenty cubits broad, and ten cubits high', 'Ten cubits long, ten cubits broad, and five cubits high', 'Thirty cubits long and fifteen cubits wide', 'Fifteen cubits in each direction', 'a', '2 Chronicles 4:1 — "Moreover he made an altar of brass, twenty cubits the length thereof, and twenty cubits the breadth thereof, and ten cubits the height thereof."'),
('2 Chronicles', 4, 'teens', 2, 'What figures were under the molten sea, supporting it?', 'Twelve oxen, three looking toward each of the four points of the compass', 'Four bronze lions on a pedestal', 'Twenty-four cherubim in two rows', 'Twelve carved palm trees', 'a', '2 Chronicles 4:4 — "It stood upon twelve oxen, three looking toward the north, and three looking toward the west, and three looking toward the south, and three looking toward the east."'),
('2 Chronicles', 4, 'teens', 3, 'How many lavers did Solomon make, and what were they used for?', 'Ten lavers to wash in, for rinsing the burnt offering', 'Seven lavers for the priests'' daily washing', 'Twelve lavers for the twelve tribes', 'Four lavers for the four cardinal points', 'a', '2 Chronicles 4:6 — "He made also ten lavers, and put five on the right hand, and five on the left, to wash in them: such things as they offered for the burnt offering they washed in them."'),
('2 Chronicles', 4, 'teens', 4, 'What was the circumference and depth of the molten sea, and how many baths did it hold?', 'Thirty cubits around, five cubits deep, holding three thousand baths', 'Twenty cubits around, three cubits deep, one thousand baths', 'Forty cubits around, eight cubits deep, five thousand baths', 'Fifteen cubits around, four cubits deep, two thousand baths', 'a', '2 Chronicles 4:5 — "And the thickness of it was an handbreadth, and the brim of it like the work of the brim of a cup...and it received and held three thousand baths."'),
('2 Chronicles', 4, 'teens', 5, 'What was made of fine gold for placing inside the most holy house?', 'An hundred basons of gold', 'The altar of incense and the table of shewbread', 'The seven-branched menorah', 'The ark overlaid with pure gold', 'a', '2 Chronicles 4:8 — "He made also an hundred basons of gold," along with the golden altar and tables.'),
-- Adults
('2 Chronicles', 4, 'adults', 1, 'What metal was used to cast all the vessels Huram made, and in what region were they cast?', 'Brass, cast in the plain of Jordan between Succoth and Zeredathah in clay ground', 'Refined silver at Jerusalem in the royal workshops', 'Bronze in the furnaces of Tyre', 'Gold mixed with bronze at Gibeon', 'a', '2 Chronicles 4:17 — "In the plain of Jordan did the king cast them, in the clay ground between Succoth and Zeredathah."'),
('2 Chronicles', 4, 'adults', 2, 'What decorative motif ran below the brim of the molten sea?', 'Flowers, resembling the work of a lily blossom', 'Cherubim and palm trees alternating', 'Pomegranates in two rows', 'Oxen heads in a continuous band', 'a', '2 Chronicles 4:5 — "And the brim of it like the work of the brim of a cup, with flowers of lilies; and it received and held three thousand baths."'),
('2 Chronicles', 4, 'adults', 3, 'What was the distinction between the use of the molten sea and the lavers?', 'The sea was for the priests to wash in while the lavers were for washing what was used in the burnt offering', 'The sea was for ritually purifying new vessels and the lavers for daily priestly washing', 'The sea held water for drinking and lavers for ceremonial sprinkling', 'The sea served the inner court and lavers served the outer court only', 'a', '2 Chronicles 4:6 — "The sea was for the priests to wash in...and such things as they offered for the burnt offering they washed in them."'),
('2 Chronicles', 4, 'adults', 4, 'What summary statement describes the quantity of brass used in all these furnishings?', 'The weight of the brass could not be found out, it was so great', 'Three hundred talents of brass in total', 'More brass than any king had ever used', 'The brass was weighed and recorded by the Levites', 'a', '2 Chronicles 4:18 — "Thus Solomon made all these vessels in great abundance: for the weight of the brass could not be found out."'),
('2 Chronicles', 4, 'adults', 5, 'What were the four categories of golden items Solomon made for inside the temple?', 'The golden altar, the tables with the shewbread, the candlesticks with their lamps, and the flowers, lamps, and tongs of pure gold', 'Ark, altar, table, and menorah', 'Basons, cups, snuffers, and bowls', 'Doors, veil hooks, cherubim, and pillars', 'a', '2 Chronicles 4:19 — "And Solomon made all the vessels that were for the house of God, the golden altar also, and the tables whereon the shewbread was set."'),
('2 Chronicles', 4, 'adults', 6, 'What courts did Solomon make for the temple complex?', 'The court of the priests and the great court, with doors overlaid with brass', 'The inner court and the outer court of the Gentiles', 'The court of women and the court of Israel', 'The upper court and the lower court by the gate', 'a', '2 Chronicles 4:9 — "Furthermore he made the court of the priests, and the great court, and doors for the court, and overlaid the doors of them with brass."'),
('2 Chronicles', 4, 'adults', 7, 'In addition to the major furnishings, what smaller golden items did Huram complete for the temple?', 'The pots, shovels, and flesh-hooks, and all their instruments', 'The rings on the staves of the ark', 'The curtain hooks and wall fittings', 'The incense pans and oil containers', 'a', '2 Chronicles 4:16 — "The pots also, and the shovels, and the fleshhooks, and all their instruments, did Huram his father make to king Solomon for the house of the LORD of bright brass."'),
('2 Chronicles', 4, 'adults', 8, 'What does the phrase "Solomon made all these vessels in great abundance" (4:18) communicate about the temple economy?', 'It shows that God''s house was furnished with extravagant generosity, echoing the principle that nothing should be withheld from the LORD', 'It was a display of political power to impress foreign kings', 'It was necessary to replace Mosaic tabernacle vessels which had worn out', 'It reflected the surplus of Solomon''s treasury that needed to be spent', 'a', '2 Chronicles 4:18 — "Thus Solomon made all these vessels in great abundance: for the weight of the brass could not be found out," signifying lavish devotion to God''s worship.');

-- ═══ 2 Chronicles Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 5, 'kids', 1, 'What was brought into the temple when it was finished?', 'The ark of the covenant of the LORD', 'The golden altar of incense', 'The tablets of Moses', 'The tabernacle of Moses', 'a', '2 Chronicles 5:2 — "Then Solomon assembled the elders of Israel...to bring up the ark of the covenant of the LORD out of the city of David."'),
('2 Chronicles', 5, 'kids', 2, 'What happened when the trumpeters and singers praised God at the dedication?', 'A cloud filled the house of the LORD', 'Fire came down from heaven', 'A great earthquake shook the temple', 'All the people fell on their faces', 'a', '2 Chronicles 5:13-14 — "Then the house was filled with a cloud, even the house of the LORD."'),
('2 Chronicles', 5, 'kids', 3, 'What were inside the ark when it was placed in the most holy place?', 'The two tables of stone which Moses put therein at Horeb', 'The pot of manna and Aaron''s rod', 'The priestly garments of Aaron', 'The original tabernacle carvings', 'a', '2 Chronicles 5:10 — "There was nothing in the ark save the two tables which Moses put therein at Horeb."'),
-- Teens
('2 Chronicles', 5, 'teens', 1, 'At what feast was the ark brought into the temple?', 'The feast of the seventh month', 'The feast of Passover', 'The feast of Pentecost', 'The feast of Tabernacles', 'a', '2 Chronicles 5:3 — "Wherefore all the men of Israel assembled themselves unto the king in the feast which was in the seventh month."'),
('2 Chronicles', 5, 'teens', 2, 'Who carried the ark into the temple?', 'The priests', 'The Levites with staves', 'Solomon and the elders together', 'The sons of Asaph', 'a', '2 Chronicles 5:7 — "And the priests brought in the ark of the covenant of the LORD unto his place, to the oracle of the house, into the most holy place."'),
('2 Chronicles', 5, 'teens', 3, 'How many sheep and oxen were sacrificed when the ark was brought up, so great that they could not be counted?', 'Sheep and oxen that could not be told nor numbered for multitude', 'One thousand oxen and ten thousand sheep', 'Seven bulls and seven rams', 'Twenty-two thousand cattle and one hundred and twenty thousand sheep', 'a', '2 Chronicles 5:6 — "Also king Solomon, and all the congregation of Israel that were assembled unto him before the ark, sacrificed sheep and oxen, which could not be told nor numbered for multitude."'),
('2 Chronicles', 5, 'teens', 4, 'What song did the singers and musicians sing when the cloud filled the temple?', 'For he is good; for his mercy endureth for ever', 'Blessed is the name of the LORD forever', 'The LORD reigneth, let the earth rejoice', 'How amiable are thy tabernacles, O LORD of hosts', 'a', '2 Chronicles 5:13 — "They lifted up their voice...and praised the LORD, saying, For he is good; for his mercy endureth for ever."'),
('2 Chronicles', 5, 'teens', 5, 'Why could the priests not stand to minister after the ark was brought in?', 'The glory of the LORD had filled the house of God', 'They were overcome with the weight of the offering', 'The king commanded them to stand aside', 'The smoke of the incense blinded their eyes', 'a', '2 Chronicles 5:14 — "So that the priests could not stand to minister by reason of the cloud: for the glory of the LORD had filled the house of God."'),
-- Adults
('2 Chronicles', 5, 'adults', 1, 'What were the staves of the ark and where could they be seen when the ark rested in the most holy place?', 'The staves were so long that the ends of them were seen from the holy place before the oracle, but not outward, and they are there unto this day', 'The staves were removed once the ark was in place', 'The staves extended outside the temple veil', 'The staves were kept separately in the priests'' chambers', 'a', '2 Chronicles 5:9 — "And the staves were so long, that the ends of the staves were seen from the ark before the oracle; but they were not seen without. And there it is unto this day."'),
('2 Chronicles', 5, 'adults', 2, 'What was the exact assembly and who were brought together for the dedication of the ark?', 'Solomon assembled all the elders of Israel, all the heads of the tribes, and the chief of the fathers of the children of Israel unto Jerusalem', 'Only the priests and Levites were summoned', 'All fighting men from twenty years old and upward', 'The tribal representatives and their households', 'a', '2 Chronicles 5:2 — "Then Solomon assembled the elders of Israel, and all the heads of the tribes, the chief of the fathers of the children of Israel, unto Jerusalem."'),
('2 Chronicles', 5, 'adults', 3, 'What was the arrangement of the Levitical musicians who sang and played at the dedication?', 'All the Levitical singers — Asaph, Heman, Jeduthun and their sons and brethren — clothed in white linen with cymbals, psalteries, and harps, with 120 priests sounding trumpets', 'Only the sons of Asaph played while the priests stood silent', 'Seven priests with seven trumpets led the procession', 'The singers stood in the inner court while priests played outside', 'a', '2 Chronicles 5:12 — "Also the Levites which were the singers...clothed in white linen, having cymbals and psalteries and harps, stood at the east end of the altar, and with them an hundred and twenty priests sounding with trumpets."'),
('2 Chronicles', 5, 'adults', 4, 'What theological statement is made by the cloud filling the temple after the music of praise?', 'The divine glory manifestly took up residence in the house, confirming that God accepted the worship and the dwelling place', 'It was a natural weather phenomenon at that season of the year', 'It was a warning to the priests to be more careful in their service', 'It symbolised the hidden mystery of God that cannot be revealed', 'a', '2 Chronicles 5:13-14 — "The house was filled with a cloud, even the house of the LORD; So that the priests could not stand to minister by reason of the cloud: for the glory of the LORD had filled the house of God."'),
('2 Chronicles', 5, 'adults', 5, 'The absence of any contents in the ark except the two tablets echoes what about Israel''s covenant identity?', 'That the covenant law of God, not ritual objects, was the heart of Israel''s relationship with the LORD', 'That the manna and rod had decayed over time and were removed', 'That the tablets were the only items that survived the wilderness', 'That the Levites had stored the other items elsewhere for safekeeping', 'a', '2 Chronicles 5:10 — "There was nothing in the ark save the two tables which Moses put therein at Horeb, when the LORD made a covenant with the children of Israel."'),
('2 Chronicles', 5, 'adults', 6, 'What does the bringing of the tabernacle along with the ark indicate about this dedication event?', 'All the holy vessels of the tabernacle were also gathered and deposited, signifying the transfer of all Mosaic worship heritage into the permanent temple', 'The tabernacle was destroyed once the ark was removed', 'The tabernacle was kept in a separate shrine outside Jerusalem', 'The tabernacle was sent to Gibeon to remain there permanently', 'a', '2 Chronicles 5:5 — "And they brought up the ark, and the tabernacle of the congregation, and all the holy vessels that were in the tabernacle, these did the priests and the Levites bring up."'),
('2 Chronicles', 5, 'adults', 7, 'What position in the temple did the ark occupy, and what was placed above it?', 'It was set under the wings of the cherubims in the most holy place, with the cherubims covering the ark and its staves', 'It stood in the centre of the holy place facing the altar', 'It was placed directly before the golden altar of incense', 'It was set upon the rock of Moriah at the base of the altar', 'a', '2 Chronicles 5:7-8 — "The priests brought in the ark...to the oracle...And the cherubims spread forth their wings over the place of the ark, and the cherubims covered the ark and the staves thereof above."'),
('2 Chronicles', 5, 'adults', 8, 'What is the typological significance of the cloud of glory filling the temple in relation to the Mosaic tabernacle?', 'It exactly repeats the pattern of Exodus 40 where the cloud filled the tabernacle after its completion, showing God''s faithful continuity', 'It was a unique miracle never seen before or since', 'It replaced the fire that had appeared at Sinai', 'It was prophesied by David in the Psalms', 'a', 'Just as in Exodus 40:34 — "Then a cloud covered the tent of the congregation," so in 2 Chronicles 5:13-14 the cloud of the LORD''s glory filled the completed temple, confirming divine acceptance.');

-- ═══ 2 Chronicles Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 6, 'kids', 1, 'What did Solomon say the LORD chose to dwell in?', 'The thick darkness', 'A pillar of fire', 'A bright cloud', 'The most holy place', 'a', '2 Chronicles 6:1 — "Then said Solomon, The LORD hath said that he would dwell in the thick darkness."'),
('2 Chronicles', 6, 'kids', 2, 'What did Solomon do before all the people when he prayed?', 'He kneeled down upon his knees and spread forth his hands toward heaven', 'He stood on a high mountain', 'He lay face down on the ground', 'He sat on his throne', 'a', '2 Chronicles 6:13 — "And kneeled down upon his knees before all the congregation of Israel, and spread forth his hands toward heaven."'),
('2 Chronicles', 6, 'kids', 3, 'Solomon said the heaven of heavens cannot contain God. What could the temple do even less?', 'How much less this house which I have built', 'Not even the whole earth could contain God', 'The ark itself could not hold him', 'No building of stone or wood could contain him', 'a', '2 Chronicles 6:18 — "But will God in very deed dwell with men on the earth? behold, heaven and the heaven of heavens cannot contain thee; how much less this house which I have built!"'),
-- Teens
('2 Chronicles', 6, 'teens', 1, 'What was the scaffold that Solomon made, and what were its dimensions?', 'A brasen scaffold five cubits long, five broad, and three cubits high, set in the court', 'A wooden platform of ten cubits on every side', 'A stone pulpit at the entrance to the temple', 'A raised altar of brass in the inner court', 'a', '2 Chronicles 6:13 — "For Solomon had made a brasen scaffold, of five cubits long, and five cubits broad, and three cubits high, and had set it in the midst of the court."'),
('2 Chronicles', 6, 'teens', 2, 'What had God told David about who would build the temple?', 'Thy son which shall come forth out of thy loins, he shall build the house for my name', 'David himself would build it if he was worthy', 'The whole nation together would build it', 'No man but God himself would build his house', 'a', '2 Chronicles 6:9 — "Notwithstanding thou shalt not build the house; but thy son which shall come forth out of thy loins, he shall build the house for my name."'),
('2 Chronicles', 6, 'teens', 3, 'In his prayer, what did Solomon ask God to do when Israel was defeated in battle because of sin and then returned to God?', 'Hear from heaven and forgive the sin of thy people Israel and bring them again unto the land', 'Give them a sign to show they were forgiven', 'Send an angel to fight for them', 'Restore their crops and remove the famine', 'a', '2 Chronicles 6:24-25 — "Then hear thou from the heavens, and forgive the sin of thy people Israel, and bring them again unto the land which thou gavest to them."'),
('2 Chronicles', 6, 'teens', 4, 'What does Solomon ask God to do regarding the foreigner who is not of Israel when he prays toward the temple?', 'Hear from heaven and do according to all that the stranger calleth to thee for, that all people may know thy name', 'Send the stranger away unless he converts to Israel', 'Answer his prayer only if a priest intercedes for him', 'Grant him the same blessing as the children of Israel', 'a', '2 Chronicles 6:33 — "Hear thou from the heavens, even from thy dwelling place, and do according to all that the stranger calleth to thee for; that all people of the earth may know thy name."'),
('2 Chronicles', 6, 'teens', 5, 'What petition did Solomon make about Israel''s armies when they go to battle and pray toward the city and temple?', 'Hear from heaven and maintain their cause', 'Give them victory over every enemy', 'Send angels to fight before them', 'Pour out thy wrath on their enemies', 'a', '2 Chronicles 6:34-35 — "If thy people go out to war against their enemies by the way that thou shalt send them, and they pray unto thee...then hear thou from the heavens their prayer and their supplication, and maintain their cause."'),
-- Adults
('2 Chronicles', 6, 'adults', 1, 'What was the foundation of Solomon''s prayer — what covenant did he invoke at the opening of his supplication?', 'The covenant with David that there would never fail a man to sit before God upon the throne of Israel, if his children take heed to walk in God''s law', 'The Mosaic covenant at Sinai given to all Israel', 'The covenant with Abraham that his seed would inherit the land', 'The covenant of peace made with Phinehas', 'a', '2 Chronicles 6:16 — "Now therefore, O LORD God of Israel, keep with thy servant David my father that which thou hast promised him."'),
('2 Chronicles', 6, 'adults', 2, 'What was the precise condition stated in the Davidic covenant that Solomon recited to God?', 'There shall not fail thee a man in my sight to sit upon the throne of Israel — yet so that thy children take heed to their way to walk in my law as thou hast walked before me', 'The throne would stand forever with no conditions attached', 'The covenant required only that sacrifices never cease', 'God promised to keep the covenant regardless of their behavior', 'a', '2 Chronicles 6:16 — "Yet so that thy children take heed to their way to walk in my law, as thou hast walked before me."'),
('2 Chronicles', 6, 'adults', 3, 'How many distinct petitions or situations does Solomon address in his prayer, showing its comprehensive scope?', 'Seven petitions covering oath-taking, defeat in battle, drought, famine or plague, the foreigner, battle, and exile', 'Three petitions for sin, battle, and foreign nations', 'Ten petitions covering all areas of the law', 'Five petitions for the five types of sacrifice', 'a', '2 Chronicles 6:22-39 — Solomon addresses seven situations: oath disputes (v.22), military defeat (v.24), drought (v.26), famine or pestilence (v.28), the foreigner (v.32), battle (v.34), and captivity (v.36).'),
('2 Chronicles', 6, 'adults', 4, 'What universal theological statement does Solomon make about human sinfulness in his prayer?', 'There is no man which sinneth not', 'All have sinned and fallen short of God''s glory', 'Man''s heart is desperately wicked above all things', 'The imagination of man''s heart is evil from his youth', 'a', '2 Chronicles 6:36 — "For there is no man which sinneth not," acknowledging universal human sinfulness as the premise for the need of divine forgiveness.'),
('2 Chronicles', 6, 'adults', 5, 'What specific act of forgiveness did Solomon request for the captives who returned to God in the land of their enemies?', 'Forgive thy people, have compassion upon them who carried them captive, and maintain their cause', 'Destroy the nations that took them captive', 'Send a deliverer to bring them home immediately', 'Restore their property and honour among the nations', 'a', '2 Chronicles 6:39 — "Then hear thou from the heavens, even from thy dwelling place, their prayer and their supplications, and maintain their cause, and forgive thy people which have sinned against thee."'),
('2 Chronicles', 6, 'adults', 6, 'What does Solomon''s statement "heaven and the heaven of heavens cannot contain thee" (6:18) reveal about Solomon''s theology?', 'He held a transcendent view of God — God cannot be confined to any place — making the temple a place for prayer toward God rather than God''s geographic prison', 'He was questioning whether the temple project was worthwhile', 'He was responding to pagan critics who said Israel''s God lived in a box', 'He was citing a Mosaic teaching about God''s omnipresence', 'a', '2 Chronicles 6:18 — "But will God in very deed dwell with men on the earth? behold, heaven and the heaven of heavens cannot contain thee; how much less this house which I have built!"'),
('2 Chronicles', 6, 'adults', 7, 'What was the posture and platform arrangement during Solomon''s prayer, and what does it signify?', 'He stood upon a brasen scaffold in the court, then kneeled with hands spread toward heaven before all the congregation', 'He prayed privately inside the most holy place', 'He stood at the altar of burnt offering with the priests around him', 'He prayed from his throne in the palace overlooking the temple', 'a', '2 Chronicles 6:12-13 — "And he stood before the altar of the LORD in the presence of all the congregation of Israel, and spread forth his hands...kneeled down upon his knees before all the congregation of Israel."'),
('2 Chronicles', 6, 'adults', 8, 'What does Solomon''s petition for the foreigner (6:32-33) reveal about the intended scope of the temple''s ministry?', 'The temple was intended as a house of prayer for all peoples of the earth, not just Israel, "that all people of the earth may know thy name"', 'Foreigners were welcome only if they converted to Judaism first', 'The petition was a diplomatic courtesy with no theological significance', 'Solomon was concerned only with trade partners from Tyre and Egypt', 'a', '2 Chronicles 6:33 — "That all people of the earth may know thy name, and fear thee, as doth thy people Israel, and may know that this house which I have built is called by thy name."');

-- ═══ 2 Chronicles Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 7, 'kids', 1, 'What came down from heaven when Solomon finished praying?', 'Fire', 'Rain', 'An angel', 'A cloud of smoke', 'a', '2 Chronicles 7:1 — "Now when Solomon had made an end of praying, the fire came down from heaven, and consumed the burnt offering and the sacrifices."'),
('2 Chronicles', 7, 'kids', 2, 'What did all the people do when they saw the fire come down from heaven?', 'They bowed themselves with their faces to the ground upon the pavement and worshipped', 'They ran away in fear', 'They shouted and blew their trumpets', 'They offered more sacrifices immediately', 'a', '2 Chronicles 7:3 — "And when all the children of Israel saw how the fire came down...they bowed themselves with their faces to the ground upon the pavement, and worshipped."'),
('2 Chronicles', 7, 'kids', 3, 'What is the most famous verse from this chapter about what God''s people should do when things go wrong?', 'If my people, which are called by my name, shall humble themselves, and pray, and seek my face, and turn from their wicked ways, then will I hear from heaven', 'Seek the LORD while he may be found', 'Repent and do the first works', 'Draw near to God and he will draw near to you', 'a', '2 Chronicles 7:14 — "If my people, which are called by my name, shall humble themselves, and pray, and seek my face, and turn from their wicked ways; then will I hear from heaven, and will forgive their sin, and will heal their land."'),
-- Teens
('2 Chronicles', 7, 'teens', 1, 'How many animals were sacrificed at the dedication feast that Solomon and all Israel kept?', 'Twenty and two thousand oxen, and an hundred and twenty thousand sheep', 'A thousand oxen and ten thousand sheep', 'Seven bulls and seven rams per day for seven days', 'Fifty thousand oxen and one hundred thousand sheep', 'a', '2 Chronicles 7:5 — "And king Solomon offered a sacrifice of twenty and two thousand oxen, and an hundred and twenty thousand sheep: so the king and all the people dedicated the house of God."'),
('2 Chronicles', 7, 'teens', 2, 'For how many days was the dedication feast celebrated in total?', 'Fourteen days and then on the twenty-third day he sent the people away', 'Seven days only', 'Twenty-one days', 'Thirty days', 'a', '2 Chronicles 7:9 — "And in the eighth day they made a solemn assembly: for they kept the dedication of the altar seven days, and the feast seven days. And on the three and twentieth day of the seventh month he sent the people away."'),
('2 Chronicles', 7, 'teens', 3, 'When did God appear to Solomon the second time in this chapter?', 'At night', 'At noon when the sun was highest', 'During the morning sacrifice', 'On the last day of the feast', 'a', '2 Chronicles 7:12 — "And the LORD appeared to Solomon by night, and said unto him, I have heard thy prayer, and have chosen this place to myself for an house of sacrifice."'),
('2 Chronicles', 7, 'teens', 4, 'What three things does God promise to do if his people humble themselves, pray, seek his face, and turn from wicked ways?', 'Hear from heaven, forgive their sin, and heal their land', 'Give them rain, peace, and victory over enemies', 'Send his spirit, restore their crops, and bless their children', 'Open the windows of heaven, rebuke the devourer, and enlarge their borders', 'a', '2 Chronicles 7:14 — "Then will I hear from heaven, and will forgive their sin, and will heal their land."'),
('2 Chronicles', 7, 'teens', 5, 'What warning did God give Solomon about what would happen if Israel turned away and served other gods?', 'He would pluck them up by the roots from the land, cast off the house, and make it a proverb and a byword among all nations', 'He would send foreign armies immediately', 'He would stop the rain for three years', 'He would remove the king from the throne at once', 'a', '2 Chronicles 7:20 — "Then will I pluck them up by the roots out of my land which I have given them; and this house, which I have sanctified for my name, will I cast out of my sight, and will make it to be a proverb and a byword among all nations."'),
-- Adults
('2 Chronicles', 7, 'adults', 1, 'What did the glory of the LORD do after the fire consumed the offering, and what was the implication for the priests?', 'The glory of the LORD filled the house so that the priests could not enter into the house of the LORD', 'The glory departed after confirming the sacrifice', 'The glory appeared as a pillar of fire above the altar', 'The glory dwelt in the ark and the priests carried it in procession', 'a', '2 Chronicles 7:2 — "And the priests could not enter into the house of the LORD, because the glory of the LORD had filled the LORD''s house."'),
('2 Chronicles', 7, 'adults', 2, 'What role did the Levitical musicians play during the dedication, and what instruments were specified?', 'All the Levites with instruments of music praised the LORD, and the priests sounded trumpets opposite them while all Israel stood', 'Only the sons of Asaph played with harps and lyres', 'The priests used only the silver trumpets Moses had made', 'The people sang without instruments', 'a', '2 Chronicles 7:6 — "And the priests waited on their offices: the Levites also with instruments of musick of the LORD, which David the king had made to praise the LORD...and the priests sounded trumpets before them."'),
('2 Chronicles', 7, 'adults', 3, 'What caused the brasen altar to be insufficient for the dedication sacrifices, and how was the problem solved?', 'The altar was too small for all the burnt offerings, so Solomon hallowed the middle of the court before the house and offered burnt offerings there', 'The fire on the altar went out and could not be relit', 'The altar broke under the weight of the offerings', 'The priests were too few to service the altar alone', 'a', '2 Chronicles 7:7 — "Moreover Solomon hallowed the middle of the court that was before the house of the LORD: for there he offered burnt offerings, and the fat of the peace offerings, because the brasen altar which Solomon had made was not able to receive the burnt offerings."'),
('2 Chronicles', 7, 'adults', 4, 'What was the full extent of the territory from which the great congregation came for the dedication feast?', 'From the entering in of Hamath unto the river of Egypt', 'From Dan to Beersheba', 'From Egypt to the Euphrates river', 'From the wilderness of Sinai to the sea of the Philistines', 'a', '2 Chronicles 7:8 — "Also at the same time Solomon kept the feast seven days, and all Israel with him, a very great congregation, from the entering in of Hamath unto the river of Egypt."'),
('2 Chronicles', 7, 'adults', 5, 'In God''s second appearance to Solomon, what did God say he had chosen and sanctified?', 'This house that Solomon had built, for God''s name to be there forever, and his eyes and his heart would be there perpetually', 'Jerusalem as the eternal capital of the kingdom', 'The Davidic line to be kings forever', 'The altar as the place where prayer would be heard', 'a', '2 Chronicles 7:16 — "For now have I chosen and sanctified this house, that my name may be there for ever: and mine eyes and mine heart shall be there perpetually."'),
('2 Chronicles', 7, 'adults', 6, 'What condition does God set for Solomon''s personal dynasty as distinct from the national covenant of 7:14?', 'If Solomon walks before God as David walked, doing all that God commanded, and keeping statutes and judgments, then God will establish the throne of his kingdom as covenanted with David', 'The dynasty would continue automatically regardless of obedience', 'Only the building of the temple determined the dynasty''s future', 'The covenant would be renewed with each successive king', 'a', '2 Chronicles 7:17-18 — "If thou wilt walk before me...then will I establish the throne of thy kingdom, according as I have covenanted with David thy father."'),
('2 Chronicles', 7, 'adults', 7, 'What would the nations say about the destroyed temple, and what would be the divine answer that gives the reason?', 'Why hath the LORD done thus unto this land, and unto this house? And it shall be answered: Because they forsook the LORD God of their fathers', 'That the temple was weaker than the gods of the nations', 'That Israel had no God to protect them', 'That Solomon''s wisdom failed in the end', 'a', '2 Chronicles 7:21-22 — "And this house, which is high, shall be an astonishment to every one that passeth by it...And it shall be answered, Because they forsook the LORD God of their fathers."'),
('2 Chronicles', 7, 'adults', 8, 'What is the theological structure of 2 Chronicles 7:14 as a covenantal formula, identifying each element?', 'Condition (humble, pray, seek, turn) → Promise (hear, forgive, heal) — a classic covenant if-then structure requiring human response for divine action', 'An unconditional promise of healing regardless of behavior', 'A priestly formula for the Day of Atonement ritual', 'A prophecy about the end times only, not for Solomon''s generation', 'a', '2 Chronicles 7:14 — "If my people...shall humble themselves, and pray, and seek my face, and turn from their wicked ways; THEN will I hear from heaven, and will forgive their sin, and will heal their land," showing the conditional nature of covenant blessing.');

-- ═══ 2 Chronicles Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 8, 'kids', 1, 'How long did it take Solomon to build his two great projects?', 'Twenty years', 'Seven years', 'Forty years', 'Thirty years', 'a', '2 Chronicles 8:1 — "And it came to pass at the end of twenty years, wherein Solomon had built the house of the LORD, and his own house."'),
('2 Chronicles', 8, 'kids', 2, 'What did Solomon do to the cities that Huram had given him?', 'He built them, and caused the children of Israel to dwell there', 'He abandoned them as unusable', 'He gave them to the Levites', 'He sold them back to Huram', 'a', '2 Chronicles 8:2 — "That the cities which Huram had restored to Solomon, Solomon built them, and caused the children of Israel to dwell there."'),
('2 Chronicles', 8, 'kids', 3, 'Where did Solomon build a fleet of ships?', 'Ezion-geber, beside Eloth at the Red Sea', 'The Mediterranean port of Joppa', 'The harbour of Tyre', 'The great sea near Ashdod', 'a', '2 Chronicles 8:17 — "Then went Solomon to Ezion-geber, and to Eloth, at the sea side in the land of Edom."'),
-- Teens
('2 Chronicles', 8, 'teens', 1, 'What did Solomon do with the non-Israelite peoples who remained in the land?', 'He made them pay tribute and serve as bond labourers, but did not make Israelites servants for the work', 'He drove them all out of the land', 'He incorporated them into the twelve tribes', 'He put them in charge of the temple service', 'a', '2 Chronicles 8:8-9 — "But of their children, who were left after them in the land, whom the children of Israel consumed not, them did Solomon make to pay tribute...But of the children of Israel did Solomon make no servants for his work."'),
('2 Chronicles', 8, 'teens', 2, 'Why did Pharaoh''s daughter move from the city of David to her own house that Solomon built for her?', 'Because Solomon said no wife shall dwell in the house of David king of Israel, because the places the ark had come to are holy', 'Because she preferred a larger residence', 'Because the city of David was too crowded', 'Because David''s palace was given to the priests', 'a', '2 Chronicles 8:11 — "My wife shall not dwell in the house of David king of Israel, because the places are holy, whereunto the ark of the LORD hath come."'),
('2 Chronicles', 8, 'teens', 3, 'What did Solomon build at Baalath and Tadmor in connection with his defense strategy?', 'Storage cities, chariot cities, and cities for his horsemen throughout his territory', 'Watchtowers on the borders of Israel', 'Temples to secure the loyalty of border peoples', 'Treasuries to store tribute from surrounding nations', 'a', '2 Chronicles 8:4-6 — "And he built Tadmor in the wilderness, and all the store cities, which he built in Hamath. Also he built Beth-horon...And Baalath, and all the store cities that Solomon had."'),
('2 Chronicles', 8, 'teens', 4, 'How did Solomon organize the priests and Levites according to David''s commandment?', 'The priests in their courses and the Levites in their courses for every duty of service, and the porters by their courses at every gate', 'He appointed new priests to replace those who had supported Adonijah', 'He organized them by tribe rather than by course', 'He put the eldest Levites in charge of each department', 'a', '2 Chronicles 8:14 — "And he appointed, according to the order of David his father, the courses of the priests to their service, and the Levites to their charges...for so had David the man of God commanded."'),
('2 Chronicles', 8, 'teens', 5, 'What ships did Huram''s servants provide for Solomon''s fleet, and what expertise did they contribute?', 'Huram''s servants were expert shipmen of the sea who sailed with Solomon''s servants to Ophir for gold', 'Egyptian sailors who knew the Red Sea routes', 'Phoenician craftsmen who built the ships at Ezion-geber', 'Levitical guides who led the navigation by scripture', 'a', '2 Chronicles 8:18 — "And Huram sent him by the hands of his servants ships, and servants that had knowledge of the sea; and they went with the servants of Solomon to Ophir, and took thence four hundred and fifty talents of gold, and brought them to king Solomon."'),
-- Adults
('2 Chronicles', 8, 'adults', 1, 'What was the amount of gold brought back from Ophir by Solomon''s fleet?', 'Four hundred and fifty talents of gold', 'One hundred and twenty talents', 'Six hundred and sixty-six talents', 'Three hundred talents per voyage', 'a', '2 Chronicles 8:18 — "And they went with the servants of Solomon to Ophir, and took thence four hundred and fifty talents of gold, and brought them to king Solomon."'),
('2 Chronicles', 8, 'adults', 2, 'What does Solomon''s statement about Pharaoh''s daughter reveal about his theology of holiness and sacred space?', 'He recognized that the holiness attached to the ark and David''s house meant a non-Israelite royal wife should not dwell in a consecrated space', 'He was simply following Egyptian court custom about housing royal wives', 'He was ashamed of the marriage and wanted to hide her', 'He feared Pharaoh''s daughter would defile the temple worship directly', 'a', '2 Chronicles 8:11 — "My wife shall not dwell in the house of David king of Israel, because the places are holy, whereunto the ark of the LORD hath come."'),
('2 Chronicles', 8, 'adults', 3, 'What range of territory did Solomon''s administrative control cover in this chapter?', 'From Hamath-zobah in the north to Ezion-geber at the Red Sea in the south, including Lebanon and the wilderness', 'Only the twelve tribes'' original territories', 'From Dan to Beersheba without expansion', 'From the Euphrates to the borders of Egypt', 'a', '2 Chronicles 8:3-4 — "And Solomon went to Hamath-zobah...And he built Tadmor in the wilderness," showing the full extent of his empire.'),
('2 Chronicles', 8, 'adults', 4, 'What was the theological basis Solomon cited for maintaining David''s prescribed order of worship?', 'David the man of God had commanded it, and Solomon did not decline from anything David commanded concerning priests and Levites and treasuries', 'The Mosaic law required the same arrangement', 'An oracle given at Gibeon specified the worship order', 'The high priest Zadok had maintained the order from David''s time', 'a', '2 Chronicles 8:14-15 — "For so had David the man of God commanded. And they departed not from the commandment of the king unto the priests and Levites concerning any matter."'),
('2 Chronicles', 8, 'adults', 5, 'What significance did Solomon attach to the three annual feasts in organizing temple worship?', 'He offered burnt offerings to the LORD in the feasts of unleavened bread, weeks, and tabernacles according to the commandment of Moses', 'He added four additional feast days to those commanded by Moses', 'He replaced the feasts with monthly offerings instead', 'He made the feasts optional for those living far from Jerusalem', 'a', '2 Chronicles 8:13 — "Even after a certain rate every day, offering according to the commandment of Moses, on the sabbaths, and on the new moons, and on the solemn feasts, three times in the year."'),
('2 Chronicles', 8, 'adults', 6, 'What was the administrative arrangement for the gatekeepers of the temple?', 'The porters were assigned by their courses at every gate, for so had David the man of God commanded', 'A single chief gatekeeper managed all entrances', 'The gatekeepers were chosen by lot each month', 'The Levitical singers also served as gatekeepers', 'a', '2 Chronicles 8:14 — "And he appointed...the porters also by their courses at every gate: for so had David the man of God commanded."'),
('2 Chronicles', 8, 'adults', 7, 'What does the Chronicler affirm about the completeness of Solomon''s obedience at the conclusion of the building phase?', 'Solomon''s work was prepared from the day of the foundation until it was finished and the house of the LORD was perfected', 'Some items remained incomplete until Rehoboam''s reign', 'The outer courts were not finished in Solomon''s lifetime', 'The temple was completed but the palace took another ten years', 'a', '2 Chronicles 8:16 — "Now all the work of Solomon was prepared unto the day of the foundation of the house of the LORD, and until it was finished. So the house of the LORD was perfected."'),
('2 Chronicles', 8, 'adults', 8, 'What is the Chronicler''s purpose in emphasizing Solomon''s administrative and building achievements in chapter 8?', 'To show that Solomon fulfilled his divinely appointed role as the builder-king whose obedience to David''s instructions secured the kingdom and worship of Israel', 'To provide a historical record for future builders', 'To justify the heavy taxation and forced labour of his reign', 'To compare Solomon favourably with the achievements of foreign kings', 'a', '2 Chronicles 8:16 — "So the house of the LORD was perfected," and 8:14-15 show Solomon''s complete fidelity to David''s order, the Chronicler''s theological emphasis on the continuity of proper worship.');

-- ═══ 2 Chronicles Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 9, 'kids', 1, 'Who came from far away to hear Solomon''s wisdom and see his riches?', 'The queen of Sheba', 'The king of Egypt', 'The queen of the Hittites', 'The princess of Tyre', 'a', '2 Chronicles 9:1 — "And when the queen of Sheba heard of the fame of Solomon, she came to prove Solomon with hard questions at Jerusalem."'),
('2 Chronicles', 9, 'kids', 2, 'What did the queen of Sheba say about Solomon after she heard his wisdom and saw his house?', 'The half of the greatness of thy wisdom was not told me, for thou exceedest the fame that I heard', 'You are truly the wisest man on earth', 'Your temple is greater than any I have seen', 'I came doubting but now I believe', 'a', '2 Chronicles 9:6 — "Howbeit I believed not their words, until I came, and mine eyes had seen it: and, behold, the one half of the greatness of thy wisdom was not told me: for thou exceedest the fame that I heard."'),
('2 Chronicles', 9, 'kids', 3, 'How many talents of gold did Solomon receive every year?', 'Six hundred threescore and six talents of gold', 'One thousand talents', 'Three hundred talents', 'Five hundred talents', 'a', '2 Chronicles 9:13 — "Now the weight of gold that came to Solomon in one year was six hundred and threescore and six talents of gold."'),
-- Teens
('2 Chronicles', 9, 'teens', 1, 'What gifts did the queen of Sheba give to Solomon?', 'An hundred and twenty talents of gold, spices in great abundance, and precious stones', 'Fifty talents of gold and ten camels of spices', 'A thousand servants and a hundred horses', 'Cedar and cypress timber and purple cloth', 'a', '2 Chronicles 9:9 — "And she gave the king an hundred and twenty talents of gold, and of spices great abundance, and precious stones."'),
('2 Chronicles', 9, 'teens', 2, 'What throne did Solomon make, and what animals were on it?', 'A great throne of ivory overlaid with gold, with six steps, a footstool, and lions standing by the stays', 'A cedar throne with golden eagles on each arm', 'A silver throne with carved cherubim at the back', 'A marble throne with twelve carved oxen beneath it', 'a', '2 Chronicles 9:17-18 — "Moreover the king made a great throne of ivory, and overlaid it with pure gold...And there were six steps to the throne, with a footstool of gold...and two lions standing by the stays."'),
('2 Chronicles', 9, 'teens', 3, 'What did Solomon make two hundred of in gold for his house in the forest of Lebanon?', 'Large shields of beaten gold, three hundred shekels of gold in each shield', 'Golden trumpets for the Levites', 'Candlesticks of pure gold', 'Drinking vessels for the feast days', 'a', '2 Chronicles 9:15 — "And king Solomon made two hundred targets of beaten gold: six hundred shekels of beaten gold went to one target."'),
('2 Chronicles', 9, 'teens', 4, 'What was the drinking vessels of king Solomon made of, and why was silver not used?', 'All the drinking vessels were of gold, and none were of silver, for silver was accounted as nothing in Solomon''s days', 'Gold mixed with ivory', 'Pure silver with gold trim', 'Bronze overlaid with gold leaf', 'a', '2 Chronicles 9:20 — "And all the drinking vessels of king Solomon were of gold...for silver was not any thing accounted of in the days of Solomon."'),
('2 Chronicles', 9, 'teens', 5, 'How long did Solomon reign in Jerusalem over all Israel?', 'Forty years', 'Thirty years', 'Twenty years', 'Fifty years', 'a', '2 Chronicles 9:30 — "And Solomon reigned in Jerusalem over all Israel forty years."'),
-- Adults
('2 Chronicles', 9, 'adults', 1, 'What was the theological observation that the queen of Sheba made about the source of Solomon''s blessing?', 'Blessed be the LORD thy God, which delighted in thee to set thee on his throne, to be king for the LORD thy God: because thy God loved Israel, he made thee king over them', 'Solomon''s wisdom came from his diligent study of the law', 'The gods of Israel were greater than all other gods', 'Israel''s success proved the superiority of the Davidic lineage', 'a', '2 Chronicles 9:8 — "Blessed be the LORD thy God, which delighted in thee to set thee on his throne, to be king for the LORD thy God: because thy God loved Israel, to establish them for ever, therefore made he thee king over them."'),
('2 Chronicles', 9, 'adults', 2, 'What did the queen of Sheba''s happiness imply about the relationship between Solomon''s wisdom and his attendants?', 'Happy are thy men, and happy are these thy servants, which stand continually before thee, and hear thy wisdom — proximity to wisdom brings blessing', 'The servants were happy because of their generous wages', 'The servants were content because of Solomon''s just governance', 'The attendants rejoiced because of the grandeur of the temple', 'a', '2 Chronicles 9:7 — "Happy are thy men, and happy are these thy servants, which stand continually before thee, and hear thy wisdom."'),
('2 Chronicles', 9, 'adults', 3, 'What was the fleet of Huram and Solomon''s servants bringing along with gold from Ophir?', 'Almug trees and precious stones', 'Spices and ivory and peacocks', 'Purple cloth and fine linen', 'Horses and chariots', 'a', '2 Chronicles 9:10-11 — "And the servants also of Huram, and the servants of Solomon, which brought gold from Ophir, brought algum trees and precious stones...And the king made of the algum trees terraces to the house of the LORD."'),
('2 Chronicles', 9, 'adults', 4, 'How does the Chronicler describe the scope of Solomon''s wisdom — what did all the kings of the earth seek?', 'All the kings of the earth sought the presence of Solomon, to hear his wisdom that God had put in his heart', 'The kings of the east and west sent ambassadors to study Israel''s law', 'All kings feared Solomon and sent tribute to avoid war', 'The kings sought alliance with Solomon for his military strength', 'a', '2 Chronicles 9:23 — "And all the kings of the earth sought the presence of Solomon, to hear his wisdom, that God had put in his heart."'),
('2 Chronicles', 9, 'adults', 5, 'What was the tribute system that supported Solomon''s annual income of 666 talents, beyond direct gold?', 'All the kings of Arabia and the governors of the country brought gold and silver in addition to merchants and traders', 'Taxation on the twelve tribes alone', 'Income from the temple treasury offerings', 'Trade monopoly from the Ophir fleet exclusively', 'a', '2 Chronicles 9:14 — "Beside that which chapmen and merchants brought. And all the kings of Arabia and governors of the country brought gold and silver to Solomon."'),
('2 Chronicles', 9, 'adults', 6, 'What was unique about the steps and the throne of Solomon among all kingdoms?', 'There was no kingdom where the like was made — the throne had twelve lions standing on six steps with no such throne in any kingdom', 'It was made of a single piece of ivory from a giant elephant', 'It was designed by the craftsman Huram-abi himself', 'It could be dismantled and transported when the king travelled', 'a', '2 Chronicles 9:19 — "And twelve lions stood there on the one side and on the other upon the six steps. There was not the like made in any kingdom."'),
('2 Chronicles', 9, 'adults', 7, 'What does the record of Solomon''s death formula tell us, and where can more details be found?', 'His acts, first and last, are written in the book of Nathan the prophet, and in the prophecy of Ahijah the Shilonite, and in the visions of Iddo the seer', 'They are only recorded in 1 Kings with no additional sources', 'A separate royal chronicle kept by the high priest', 'The book of the chronicles of the kings of Judah', 'a', '2 Chronicles 9:29 — "Now the rest of the acts of Solomon, first and last, are they not written in the book of Nathan the prophet, and in the prophecy of Ahijah the Shilonite, and in the visions of Iddo the seer?"'),
('2 Chronicles', 9, 'adults', 8, 'Why is the Chronicler''s account of Solomon notably different from 1 Kings in what it omits?', 'The Chronicler omits Solomon''s apostasy, foreign wives, and idolatry, focusing instead on his role as temple builder and wise king — a deliberately positive portrait for post-exilic Israel', 'The Chronicler had access to different source documents that lacked the negative material', 'The negative material was added to Kings much later by an editor', 'The Chronicler wrote before Solomon''s apostasy was known to the scribes', 'a', 'Comparison of 2 Chronicles 9 with 1 Kings 11 shows the Chronicler ends with Solomon''s death without mentioning apostasy, reflecting his theological purpose of presenting the ideal Davidic king for the restoration community.');

-- ═══ 2 Chronicles Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 10, 'kids', 1, 'Who asked King Rehoboam to make the people''s work easier?', 'Jeroboam and all Israel', 'The priests and Levites', 'The queen mother', 'The elders of Judah', 'a', '2 Chronicles 10:3-4 — "And they sent and called him. And Jeroboam and all Israel came and spake to Rehoboam, saying, Thy father made our yoke grievous: now therefore ease thou somewhat the grievous servitude of thy father."'),
('2 Chronicles', 10, 'kids', 2, 'Who did Rehoboam listen to instead of the wise old men?', 'The young men who had grown up with him', 'The foreign kings around Israel', 'His own servants in the palace', 'The soldiers of his army', 'a', '2 Chronicles 10:8 — "But he forsook the counsel of the old men, and took counsel with the young men that were brought up with him."'),
('2 Chronicles', 10, 'kids', 3, 'What did Rehoboam say his little finger was compared to his father''s whole body?', 'My little finger shall be thicker than my father''s loins', 'My little finger is stronger than my father''s hand', 'My little finger rules more than my father''s arm', 'My little finger weighs more than my father''s back', 'a', '2 Chronicles 10:10 — "My little finger shall be thicker than my father''s loins."'),
-- Teens
('2 Chronicles', 10, 'teens', 1, 'How long did Rehoboam ask for before giving his answer to the people''s request?', 'Three days', 'Seven days', 'One day', 'Thirty days', 'a', '2 Chronicles 10:5 — "And he said unto them, Come again unto me after three days. And the people departed."'),
('2 Chronicles', 10, 'teens', 2, 'What was the counsel of the old men who had stood before Solomon?', 'If thou be kind to this people and please them and speak good words to them they will be thy servants for ever', 'Be strong and show them who is king', 'Reduce the taxes but increase the tribute', 'Send them away without a direct answer', 'a', '2 Chronicles 10:7 — "If thou be kind to this people, and please them, and speak good words to them, they will be thy servants for ever."'),
('2 Chronicles', 10, 'teens', 3, 'What did Rehoboam threaten to use on the people instead of whips?', 'Scorpions', 'Iron rods', 'Chains', 'Fire', 'a', '2 Chronicles 10:11 — "For whereas my father put a heavy yoke upon you, I will put more to your yoke: my father chastised you with whips, but I will chastise you with scorpions."'),
('2 Chronicles', 10, 'teens', 4, 'What was the rallying cry of the ten tribes when they rejected Rehoboam?', 'To your tents, O Israel: and now, David, see to thine own house', 'We will have no king but God alone', 'Down with the house of Solomon', 'Let Jeroboam be our king by the choice of the people', 'a', '2 Chronicles 10:16 — "And when all Israel saw that the king would not hearken unto them...saying, What portion have we in David?...to your tents, O Israel."'),
('2 Chronicles', 10, 'teens', 5, 'What did the Chronicler say was the cause of Rehoboam''s refusal to listen to the people?', 'The cause was of God, that the LORD might perform his word which he spake by the hand of Ahijah the Shilonite to Jeroboam', 'Rehoboam was too proud and would not take counsel', 'The young advisors had bribed Rehoboam against the elders', 'The devil hardened his heart as God had hardened Pharaoh''s', 'a', '2 Chronicles 10:15 — "So the king hearkened not unto the people: for the cause was of God, that the LORD might perform his word, which he spake by the hand of Ahijah the Shilonite to Jeroboam."'),
-- Adults
('2 Chronicles', 10, 'adults', 1, 'Where did all Israel gather to make Rehoboam king, and why was this location significant?', 'Shechem, a historically significant city of assembly associated with the covenant renewals of Joshua''s era', 'Jerusalem, the seat of David''s dynasty', 'Gibeon, where Solomon had received wisdom from God', 'Bethel, the site of Jacob''s dream', 'a', '2 Chronicles 10:1 — "And Rehoboam went to Shechem: for to Shechem were all Israel come to make him king," echoing Joshua 24:1 and earlier covenant assemblies.'),
('2 Chronicles', 10, 'adults', 2, 'What specific contrast did Rehoboam communicate between his governance style and his father''s regarding punishment?', 'My father chastised you with whips but I will chastise you with scorpions — implying a far more severe and cruel form of discipline', 'My father taxed one tenth but I will tax one fifth', 'My father drafted one man in ten but I will draft five in ten', 'My father ruled forty years but I will rule eighty years with double the demands', 'a', '2 Chronicles 10:11 — "My father chastised you with whips, but I will chastise you with scorpions."'),
('2 Chronicles', 10, 'adults', 3, 'What was the prophecy of Ahijah the Shilonite that the kingdom division fulfilled?', 'The LORD had told Jeroboam through Ahijah that he would be given ten tribes of Israel because Solomon had forsaken God and gone after other gods', 'Ahijah had predicted a civil war after Solomon''s death', 'The division was foretold because of David''s sin with Bathsheba', 'Nathan the prophet had predicted the division in David''s time', 'a', '2 Chronicles 10:15 — "The cause was of God, that the LORD might perform his word, which he spake by the hand of Ahijah the Shilonite to Jeroboam," referring to 1 Kings 11:29-39.'),
('2 Chronicles', 10, 'adults', 4, 'What happened to Adoram (Hadoram), whom Rehoboam sent to the northern tribes after their revolt?', 'All Israel stoned him with stones that he died, and king Rehoboam made speed to get him up to his chariot to flee to Jerusalem', 'He successfully collected the tribute', 'He was taken hostage by Jeroboam', 'He escaped but was later killed in battle', 'a', '2 Chronicles 10:18 — "Then king Rehoboam sent Hadoram that was over the tribute; and the children of Israel stoned him with stones, that he died."'),
('2 Chronicles', 10, 'adults', 5, 'What does the contrast between the old men''s advice and the young men''s advice reveal about two competing theories of leadership?', 'The old men counselled servant-leadership (be kind, earn loyalty), while the young men counselled authoritarian dominance (show strength, increase burden)', 'The old men were simply more cautious while the young men were more ambitious', 'The difference was only in communication style, not in policy', 'The young men''s advice was strategically sound but poorly timed', 'a', '2 Chronicles 10:7 — "If thou be kind to this people...they will be thy servants for ever," versus 10:10-11 where the young men counselled harsher rule.'),
('2 Chronicles', 10, 'adults', 6, 'After the division, what territory remained loyal to the house of David?', 'Only Israel that dwelt in the cities of Judah did Rehoboam reign over', 'The tribes of Judah, Benjamin, and Simeon', 'All of the southern tribes plus the Levites', 'Judah alone, since Benjamin joined the north', 'a', '2 Chronicles 10:17 — "But as for the children of Israel that dwelt in the cities of Judah, Rehoboam reigned over them."'),
('2 Chronicles', 10, 'adults', 7, 'What does the division of the kingdom under Rehoboam represent theologically in the Chronicler''s narrative?', 'The inevitable consequence of Solomon''s apostasy working itself out in the next generation, fulfilling God''s prophetic word', 'Simply a political failure of Rehoboam''s inexperience', 'A natural economic conflict between the north and south', 'God''s abandonment of the Davidic covenant', 'a', '2 Chronicles 10:15 — "The cause was of God, that the LORD might perform his word," showing the division as divine judgment and covenant fulfillment, not mere political accident.'),
('2 Chronicles', 10, 'adults', 8, 'What is the literary and theological significance of the phrase "What portion have we in David?" in verse 16?', 'It echoes the exact words of Sheba''s rebellion in 2 Samuel 20:1, showing the recurring nature of northern tribal resistance to Davidic rule', 'It is a liturgical phrase used at covenant assemblies', 'It was a legal formula for dissolving a royal contract', 'It was coined by Jeroboam to rally the people emotionally', 'a', '2 Chronicles 10:16 — "What portion have we in David?" mirrors 2 Samuel 20:1, "We have no part in David," connecting Rehoboam''s crisis to earlier fault lines in the united monarchy.');

-- ═══ 2 Chronicles Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 11, 'kids', 1, 'When Rehoboam wanted to fight the northern tribes, what did God say through the prophet Shemaiah?', 'Return every man to his house, for this thing is done of me', 'Go up and fight, I will give you victory', 'Wait three years and then go to battle', 'Send an army of priests instead of soldiers', 'a', '2 Chronicles 11:4 — "Thus saith the LORD, Ye shall not go up, nor fight against your brethren: return every man to his house: for this thing is done of me."'),
('2 Chronicles', 11, 'kids', 2, 'What did Rehoboam build throughout the land of Judah to make the kingdom strong?', 'Cities for defence', 'Temples for worship', 'Schools for wisdom', 'Harbours for trade', 'a', '2 Chronicles 11:5 — "And Rehoboam dwelt in Jerusalem, and built cities for defence in Judah."'),
('2 Chronicles', 11, 'kids', 3, 'Who came from all the northern tribes to live in Judah and Jerusalem to support Rehoboam?', 'The priests and the Levites', 'The soldiers and their families', 'The merchants and traders', 'The prophets and judges', 'a', '2 Chronicles 11:13 — "And the priests and the Levites that were in all Israel resorted to him out of all their coasts."'),
-- Teens
('2 Chronicles', 11, 'teens', 1, 'How many chosen warriors did Rehoboam assemble to fight against Israel?', 'An hundred and fourscore thousand chosen men', 'Three hundred thousand fighting men', 'Fifty thousand horsemen', 'One million soldiers from all Judah', 'a', '2 Chronicles 11:1 — "And when Rehoboam was come to Jerusalem, he gathered of the house of Judah and Benjamin an hundred and fourscore thousand chosen men."'),
('2 Chronicles', 11, 'teens', 2, 'Why did the Levites leave their pastures and possessions and come to Judah and Jerusalem?', 'Because Jeroboam and his sons had cast them off from executing the priest''s office unto the LORD', 'Because the northern kingdom taxed them more heavily', 'Because Jerusalem had better temple facilities', 'Because God commanded them all to return in a vision', 'a', '2 Chronicles 11:14 — "For the Levites left their suburbs and their possession, and came to Judah and Jerusalem: for Jeroboam and his sons had cast them off from executing the priest''s office unto the LORD."'),
('2 Chronicles', 11, 'teens', 3, 'What false gods did Jeroboam appoint priests for in the north?', 'He ordained him priests for the high places, and for the devils, and for the calves which he had made', 'He set up Baal worship in every city', 'He brought back the gods of Egypt', 'He appointed priests of Molech and Ashtaroth', 'a', '2 Chronicles 11:15 — "And he ordained him priests for the high places, and for the devils, and for the calves which he had made."'),
('2 Chronicles', 11, 'teens', 4, 'How many wives and concubines did Rehoboam take?', 'Eighteen wives and sixty concubines, and begat twenty-eight sons and sixty daughters', 'Fourteen wives and thirty concubines', 'Seven wives and twelve concubines', 'Twenty wives and forty concubines', 'a', '2 Chronicles 11:21 — "And Rehoboam loved Maachah the daughter of Absalom above all his wives and his concubines: (for he took eighteen wives, and threescore concubines; and begat twenty and eight sons, and threescore daughters.)"'),
('2 Chronicles', 11, 'teens', 5, 'Whom did Rehoboam appoint as the leader among his sons, to be the successor to the throne?', 'Abijah the son of Maachah', 'His firstborn Jeush', 'Attai his third son', 'Ziza the son of Shelomith', 'a', '2 Chronicles 11:22 — "And Rehoboam made Abijah the son of Maachah the chief, to be ruler among his brethren: for he thought to make him king."'),
-- Adults
('2 Chronicles', 11, 'adults', 1, 'List the cities Rehoboam fortified as a defensive network, and what strategic pattern do they reveal?', 'Bethlehem, Etam, Tekoa, Beth-zur, Soco, Adullam, Gath, Mareshah, Ziph, Adoraim, Lachish, Azekah, Zorah, Aijalon, and Hebron — forming a ring of forts around Judah especially on the western and southern approaches', 'Only northern border towns facing Israel', 'Cities along the Jordan River as a defensive line', 'Coastal cities to protect against Philistine raids', 'a', '2 Chronicles 11:6-10 — "He built even Beth-lehem, and Etam, and Tekoa, And Beth-zur, and Shoco, and Adullam...These are the fenced cities of Judah and Benjamin," forming a defensive perimeter.'),
('2 Chronicles', 11, 'adults', 2, 'What did Rehoboam provision the fortified cities with, showing his logistical planning?', 'Shields, spears, victuals, oil, and wine, and officers over every city', 'Only weapons and soldiers without food stores', 'Gold and silver for paying mercenaries', 'Temple vessels moved from Jerusalem for safekeeping', 'a', '2 Chronicles 11:11-12 — "And he fortified the strong holds, and put captains in them, and store of victual, and of oil and wine. And in every several city he put shields and spears."'),
('2 Chronicles', 11, 'adults', 3, 'What spiritual dynamic does the Chronicler highlight about those who came from the north to Judah under Rehoboam?', 'All those from every tribe of Israel who set their hearts to seek the LORD God of Israel came to Jerusalem to sacrifice, strengthening the kingdom for three years', 'Only the Levites came south, ordinary Israelites stayed north', 'The northern emigrants were mostly merchants and craftsmen', 'The priests came only temporarily for the annual feasts', 'a', '2 Chronicles 11:16 — "And after them out of all the tribes of Israel such as set their hearts to seek the LORD God of Israel came to Jerusalem, to sacrifice unto the LORD God of their fathers."'),
('2 Chronicles', 11, 'adults', 4, 'What does the statement "they strengthened the kingdom of Judah and made Rehoboam the son of Solomon strong, three years" tell us about the nature of spiritual faithfulness and political stability?', 'Faithfulness to God''s worship brought national strength, but only lasted three years because Rehoboam eventually forsook the law', 'Three years was the standard probationary period for new kings', 'Military fortifications alone secured the kingdom for three years', 'The northern defection actually made Judah stronger long-term', 'a', '2 Chronicles 11:17 — "So they strengthened the kingdom of Judah, and made Rehoboam the son of Solomon strong, three years: for three years they walked in the way of David and Solomon."'),
('2 Chronicles', 11, 'adults', 5, 'Why did Rehoboam choose Maachah as his most beloved wife when she was not his first wife?', 'He loved Maachah the daughter of Absalom above all his wives and concubines and made her son Abijah his crown prince', 'Maachah was the daughter of a foreign king and brought a political alliance', 'She was the most beautiful of his wives', 'She was the eldest and held by custom the first rank', 'a', '2 Chronicles 11:21 — "And Rehoboam loved Maachah the daughter of Absalom above all his wives and his concubines," making her son heir apparent.'),
('2 Chronicles', 11, 'adults', 6, 'What does Rehoboam''s wise practice of distributing his sons among the fortified cities teach us about his administration?', 'He dealt wisely, distributing his many sons to all the countries of Judah and Benjamin to all the fenced cities, giving them abundant victuals — a strategy to prevent a coup and secure loyal governors', 'He exiled potential rivals to keep them from Jerusalem', 'He was following the Mosaic law about royal inheritance', 'He stationed his sons where they could learn military skills', 'a', '2 Chronicles 11:23 — "And he dealt wisely, and dispersed of all his children throughout all the countries of Judah and Benjamin, unto every fenced city: and he gave them victual in abundance."'),
('2 Chronicles', 11, 'adults', 7, 'What is the significance of Jeroboam''s priests for "the devils" (shedim, goat-demons)?', 'It indicates he instituted a syncretistic religion involving demonic cult worship, not merely a reformed Yahwism, showing the spiritual depravity of the northern kingdom from its foundation', 'It was a misunderstanding by the Chronicler of ordinary high-place worship', 'Jeroboam worshipped demons openly before all Israel', 'The shedim were minor household gods not considered dangerous', 'a', '2 Chronicles 11:15 — "And he ordained him priests for the high places, and for the devils (shedim), and for the calves which he had made," showing the northern cult''s departure from pure Yahwism.'),
('2 Chronicles', 11, 'adults', 8, 'What does the three-year period of faithfulness under Rehoboam (v.17) reveal about the Chronicler''s retribution theology?', 'The Chronicler consistently links obedience to blessing and disobedience to punishment — Rehoboam''s faithfulness brought military strength and the kingdom was strengthened, before he later forsook the law and suffered invasion', 'Three years was a fixed period of divine testing before judgment', 'The Chronicler is uncertain about the length of Rehoboam''s good period', 'Military strength came from David''s legacy, not from Rehoboam''s personal faithfulness', 'a', '2 Chronicles 11:17 — "Three years they walked in the way of David and Solomon," connected directly to their being strengthened, anticipating the contrast with chapter 12 when Rehoboam forsook the law and suffered Shishak''s invasion.');

-- ═══ 2 Chronicles Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Chronicles', 12, 'kids', 1, 'What did Rehoboam and all Israel do that caused God to let a foreign king attack them?', 'They forsook the law of the LORD', 'They stopped going to the temple', 'They refused to pay their tithes', 'They made idols of gold', 'a', '2 Chronicles 12:1 — "And it came to pass, when Rehoboam had established the kingdom, and had strengthened himself, he forsook the law of the LORD, and all Israel with him."'),
('2 Chronicles', 12, 'kids', 2, 'Who was the foreign king who came up against Jerusalem?', 'Shishak king of Egypt', 'Nebuchadnezzar king of Babylon', 'Sennacherib king of Assyria', 'Hazael king of Syria', 'a', '2 Chronicles 12:2 — "And it came to pass, that in the fifth year of king Rehoboam Shishak king of Egypt came up against Jerusalem."'),
('2 Chronicles', 12, 'kids', 3, 'What did Rehoboam and the princes do when the prophet Shemaiah told them God was punishing them?', 'They humbled themselves and said, The LORD is righteous', 'They went out to fight the Egyptian army', 'They prayed all night in the temple', 'They sent gifts to Shishak to stop him', 'a', '2 Chronicles 12:6 — "Whereupon the princes of Israel and the king humbled themselves; and they said, The LORD is righteous."'),
-- Teens
('2 Chronicles', 12, 'teens', 1, 'How large was Shishak''s army that came against Jerusalem?', 'Twelve hundred chariots, and threescore thousand horsemen, and people without number out of Egypt', 'Five hundred chariots and twenty thousand infantry', 'A million soldiers from Cush and Egypt', 'Three thousand chariots and ninety thousand foot soldiers', 'a', '2 Chronicles 12:3 — "With twelve hundred chariots, and threescore thousand horsemen: and the people were without number that came with him out of Egypt; the Lubims, the Sukkiims, and the Ethiopians."'),
('2 Chronicles', 12, 'teens', 2, 'What did God say he would do differently because they had humbled themselves?', 'He would not destroy them but grant them some deliverance, and not pour his wrath on Jerusalem by the hand of Shishak', 'He would drive out Shishak''s army in one night', 'He would send an angel to protect the temple treasury', 'He would restore all that Shishak had taken', 'a', '2 Chronicles 12:7 — "And when the LORD saw that they humbled themselves, the word of the LORD came to Shemaiah, saying, They have humbled themselves; therefore I will not destroy them, but I will grant them some deliverance."'),
('2 Chronicles', 12, 'teens', 3, 'What did Shishak take when he came to Jerusalem?', 'The treasures of the house of the LORD and the treasures of the king''s house, and the shields of gold Solomon had made', 'Only the gold from the temple altar', 'The ark of the covenant', 'The king''s throne and royal treasury', 'a', '2 Chronicles 12:9 — "So Shishak king of Egypt came up against Jerusalem, and took away the treasures of the house of the LORD, and the treasures of the king''s house; he took all: he carried away also the shields of gold which Solomon had made."'),
('2 Chronicles', 12, 'teens', 4, 'What did Rehoboam make to replace the golden shields that Shishak had taken?', 'Shields of brass', 'Shields of silver', 'Shields of iron', 'Shields of wood overlaid with bronze', 'a', '2 Chronicles 12:10 — "Instead of which king Rehoboam made shields of brass, and committed them to the hands of the chief of the guard."'),
('2 Chronicles', 12, 'teens', 5, 'What was the overall moral summary the Chronicler gave about Rehoboam''s character?', 'He did evil, because he prepared not his heart to seek the LORD', 'He was a good king who made one great mistake', 'He was neither righteous nor wicked but walked in the middle way', 'He started evil but repented and ended well', 'a', '2 Chronicles 12:14 — "And he did evil, because he prepared not his heart to seek the LORD."'),
-- Adults
('2 Chronicles', 12, 'adults', 1, 'What specific word from God did the prophet Shemaiah deliver to explain why Shishak had been permitted to succeed?', 'Ye have forsaken me, and therefore have I also left you in the hand of Shishak', 'Because thou hast not walked in the way of thy father Solomon', 'The covenant is broken and I will no longer fight for you', 'This calamity comes because thou hast made Egypt an ally', 'a', '2 Chronicles 12:5 — "Thus saith the LORD, Ye have forsaken me, and therefore have I also left you in the hand of Shishak."'),
('2 Chronicles', 12, 'adults', 2, 'What is the theological structure of "forsake-abandon" that 12:5 demonstrates in the Chronicler''s pattern?', 'When Israel forsook God, God in turn forsook (abandoned/handed over) Israel — a precise reciprocal covenant consequence showing divine justice', 'God acted arbitrarily without regard to Israel''s behavior', 'God used Egypt as a neutral instrument with no covenantal significance', 'Shishak invaded because of Solomon''s sins, not Rehoboam''s', 'a', '2 Chronicles 12:5 — "Ye have forsaken me, and therefore have I also left you," perfectly mirroring 7:22''s warning and establishing the Chronicler''s consistent pattern of immediate retribution.'),
('2 Chronicles', 12, 'adults', 3, 'What was the precise condition that led God to modify his judgment from destruction to partial deliverance?', 'Their humbling of themselves — the LORD saw that they humbled themselves and therefore granted some deliverance and would not pour out his wrath by Shishak', 'Their offering of burnt offerings at the temple', 'The intercession of the priest Shemaiah on their behalf', 'The partial faithfulness of the Levites who had not forsaken God', 'a', '2 Chronicles 12:7 — "When the LORD saw that they humbled themselves...I will not destroy them, but I will grant them some deliverance; and my wrath shall not be poured out upon Jerusalem by the hand of Shishak."'),
('2 Chronicles', 12, 'adults', 4, 'What theological lesson does the replacement of golden shields with bronze ones symbolize?', 'It visually represented the diminished glory of the kingdom under God''s discipline — gold replaced by an inferior metal symbolizes the loss that comes from spiritual compromise', 'It was a purely practical economic decision after the treasury was emptied', 'Bronze was harder and more practical for ceremonial use', 'It fulfilled a prophecy about the kingdoms declining metals as in Daniel''s statue', 'a', '2 Chronicles 12:10 — "Instead of which king Rehoboam made shields of brass," the substitution of brass for gold visually embodying the spiritual and material decline caused by Rehoboam''s unfaithfulness.'),
('2 Chronicles', 12, 'adults', 5, 'What was Shishak''s full strategic achievement in this campaign, beyond taking Jerusalem''s treasuries?', 'He took the fenced cities of Judah and came to Jerusalem, meaning Rehoboam''s entire fortification network had been breached before the capital was threatened', 'He only attacked Jerusalem without touching other cities', 'He set up a permanent garrison in Jerusalem', 'He destroyed the temple and carried off the priests', 'a', '2 Chronicles 12:4 — "And he took the fenced cities which pertained to Judah, and came to Jerusalem," showing Rehoboam''s entire defensive ring (built in ch. 11) had fallen.'),
('2 Chronicles', 12, 'adults', 6, 'What does the Chronicler say about the condition of Judah after the humbling before Shishak?', 'They were Shishak''s servants, that they might know my service and the service of the kingdoms of the countries', 'They were restored to their former strength within a year', 'They paid annual tribute to Egypt for forty years', 'They remained under Egyptian occupation until Solomon''s death', 'a', '2 Chronicles 12:8 — "Nevertheless they shall be his servants; that they may know my service, and the service of the kingdoms of the countries," a profoundly ironic lesson about the choice between serving God and serving foreign kings.'),
('2 Chronicles', 12, 'adults', 7, 'What does God''s statement "that they may know my service, and the service of the kingdoms of the countries" (12:8) reveal about his pedagogical purpose in judgment?', 'God used Shishak''s conquest as a teaching moment — Israel would learn through comparison that serving God was far lighter than serving pagan kings, making discipline a form of instruction rather than mere punishment', 'God was abandoning Israel permanently to foreign domination', 'The statement was ironic: God was mocking Israel for their choice', 'It was a one-time lesson without broader application', 'a', '2 Chronicles 12:8 — "That they may know my service, and the service of the kingdoms of the countries," showing divine discipline as educative, designed to restore proper perspective on the relative demands of serving God versus serving human masters.'),
('2 Chronicles', 12, 'adults', 8, 'How does the Chronicler''s summary assessment of Rehoboam — "he prepared not his heart to seek the LORD" (12:14) — function as the key to understanding all of chapters 10-12?', 'It identifies the root failure as not a single act but a character disposition — a heart not oriented toward God — which explains both his foolish political decision in chapter 10 and his spiritual apostasy in chapter 12', 'It refers only to the specific incident of forsaking the law in 12:1', 'It is a formulaic condemnation the Chronicler applies to all bad kings without specific meaning', 'It means Rehoboam never attended temple services', 'a', '2 Chronicles 12:14 — "He did evil, because he prepared not his heart to seek the LORD," linking his political failures (ch. 10), fortification successes (ch. 11), and ultimate spiritual failure (ch. 12) to a single underlying issue of the heart.');
